const NewsSlider = ({
  news,
  community,
  userState,
  onSelectNews,
}: {
  news: any[];
  community?: string;
  userState?: string;
  onSelectNews: (item: any) => void;
}) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [activeIndex, setActiveIndex] = useState(0);
  const [isHovered, setIsHovered] = useState(false);

  const filteredNews = useMemo(() => {
    // News is pre-filtered and auto-tailored by HomeScreen's personalizedNews memo in response to user profile traits
    return news;
  }, [news]);

  // Auto-scroll logic: hold each news for 5 seconds (5000ms) before scrolling automatically
  useEffect(() => {
    if (filteredNews.length <= 1 || isHovered) return;

    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % filteredNews.length);
    }, 5000);

    return () => clearInterval(interval);
  }, [filteredNews.length, isHovered]);

  // Scroll to active index smoothly when index or news list changes
  useEffect(() => {
    const el = scrollRef.current;
    if (!el || filteredNews.length === 0) return;

    const childrenContainer = el.firstElementChild;
    const children = childrenContainer?.children;
    if (children && children[activeIndex]) {
      const activeChild = children[activeIndex] as HTMLElement;
      el.scrollTo({
        left: activeChild.offsetLeft - el.offsetLeft - 8,
        behavior: "smooth",
      });
    }
  }, [activeIndex, filteredNews]);

  const handleNext = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (filteredNews.length === 0) return;
    setActiveIndex((prev) => (prev + 1) % filteredNews.length);
  };

  const handlePrev = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (filteredNews.length === 0) return;
    setActiveIndex((prev) => (prev - 1 + filteredNews.length) % filteredNews.length);
  };

  const getTheme = () => {
    switch (community) {
      case "Student":
        return "border-blue-100 bg-blue-50/50";
      case "Jobs":
        return "border-indigo-100 bg-indigo-50/50";
      default:
        return "border-gray-100 bg-gray-50/50";
    }
  };

  return (
    <div className="flex flex-col gap-2 relative animate-fade-in">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-2 px-1">
        <div className="flex flex-col text-left">
          <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
            Latest for your Community
          </h3>
          <p className="text-[9px] text-[#008069] font-black uppercase tracking-tight leading-none mt-1 animate-pulse">
            Aapke profile ke anusar auto-personalized updates ✨
          </p>
        </div>
        
        {/* Navigation buttons and index count */}
        {filteredNews.length > 0 && (
          <div className="flex items-center gap-1 bg-slate-100/80 backdrop-blur px-2 py-0.5 rounded-full border border-slate-200/50">
            <button
              type="button"
              onClick={handlePrev}
              className="p-1 hover:bg-white text-slate-600 rounded-full border-0 cursor-pointer active:scale-95 transition-all"
              title="Previous News"
            >
              <ChevronLeft className="w-3.5 h-3.5" />
            </button>
            
            <span className="text-[9px] font-black text-slate-500 min-w-[28px] text-center">
              {activeIndex + 1}/{filteredNews.length}
            </span>

            <button
              type="button"
              onClick={handleNext}
              className="p-1 hover:bg-white text-slate-600 rounded-full border-0 cursor-pointer active:scale-95 transition-all"
              title="Next News"
            >
              <ChevronRight className="w-3.5 h-3.5" />
            </button>
          </div>
        )}
      </div>

      {filteredNews.length === 0 ? (
        <div className="flex flex-col items-center justify-center p-8 bg-slate-50 dark:bg-slate-900 border border-dashed border-slate-200 dark:border-slate-850 rounded-[2rem] text-center gap-2">
          <p className="text-xs font-bold text-gray-700 dark:text-gray-300">
            Sanjeet bhai, aapke profile criteria ke matching abhi koi updates nahi hain! 🔍
          </p>
        </div>
      ) : (
        <div
          ref={scrollRef}
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          className="flex overflow-x-auto scroll-smooth gap-4 pb-1.5 relative scrollbar-none snap-x"
        >
          <div className="flex gap-4 min-w-max px-1">
            {filteredNews.map((item, i) => (
              <div
                key={i}
                onClick={() => onSelectNews(item)}
                className={cn(
                  "w-[280px] p-4 rounded-[2rem] border shadow-sm flex flex-col gap-3 transition-all hover:shadow-md hover:border-emerald-300 cursor-pointer active:scale-[0.98] snap-start bg-white",
                  getTheme(),
                  i === activeIndex ? "ring-2 ring-emerald-500/20 border-emerald-400 bg-emerald-50/10 shadow-md" : ""
                )}
              >
                <div className="w-full h-32 rounded-2xl bg-white overflow-hidden border border-gray-100 relative">
                  <img
                    src={
                      item.image ||
                      `https://picsum.photos/seed/${item.id + i}/400/225`
                    }
                    alt={item.title}
                    className="w-full h-full object-cover"
                    referrerPolicy="no-referrer"
                  />
                  <div className="absolute top-2 left-2 px-2 py-0.5 bg-black/60 backdrop-blur rounded-lg text-[8px] font-black text-white uppercase tracking-widest block whitespace-nowrap">
                    {item.category}
                  </div>
                </div>
                <div className="text-left">
                  <h4 className="text-xs font-black text-gray-900 leading-tight line-clamp-2">
                    {item.title}
                  </h4>
                  <p className="text-[10px] text-gray-500 font-medium mt-1 line-clamp-1 italic">
                    {item.summary}
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Slide Indicators Navigation Dots */}
      {filteredNews.length > 0 && (
        <div className="flex justify-center items-center gap-1.5 mt-1">
          {filteredNews.map((_, i) => (
            <button
              key={i}
              onClick={() => setActiveIndex(i)}
              className={`h-1 rounded-full transition-all border-0 cursor-pointer ${
                i === activeIndex ? "w-4 bg-[#008069]" : "w-1.5 bg-slate-200 hover:bg-slate-300"
              }`}
              title={`Go to slide ${i + 1}`}
            />
          ))}
        </div>
      )}
    </div>
  );
};

