const ThinkingStepsRenderer = () => {
  const [steps, setSteps] = useState<{ text: string; status: "loading" | "complete" }[]>([
    { text: "Initializing Form Mitra AI Model... 🧠", status: "loading" },
  ]);

  useEffect(() => {
    const allSteps = [
      "Analyzing active profile community & state rules... 👤",
      "Connecting to official government NIC servers... 📡",
      "Searching latest active/open schemes & competitive exam updates... 🌐",
      "Filtering unauthorized third-party links & outdated listings... 🛡️",
      "Reasoning the absolute best guidance plan for you... 📝",
      "Formatting details in clear Hinglish & Devanagari script... 🗣️",
      "Adding final form rejection prevention tips... 👍"
    ];

    let currentIdx = 0;
    const interval = setInterval(() => {
      if (currentIdx < allSteps.length) {
        setSteps((prev) => {
          const updated = prev.map((s, idx) =>
            idx === prev.length - 1 ? { ...s, status: "complete" as const } : s
          );
          return [...updated, { text: allSteps[currentIdx], status: "loading" as const }];
        });
        currentIdx++;
      } else {
        clearInterval(interval);
      }
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="w-full bg-slate-50 border border-gray-200/60 rounded-3xl p-4 flex flex-col gap-3 text-left shadow-xs mt-2">
      <div className="flex items-center gap-2 border-b border-gray-100 pb-2 mb-1">
        <Sparkles className="w-4 h-4 text-emerald-600 animate-spin" />
        <span className="text-[10px] font-black uppercase text-emerald-800 tracking-wider">
          Mitra AI Thoughts (सोचने की प्रक्रिया) 🧠
        </span>
      </div>
      <div className="flex flex-col gap-2.5 max-h-[160px] overflow-y-auto pr-1">
        {steps.map((step, idx) => (
          <div key={idx} className="flex items-start gap-2 text-xs text-gray-700 animate-fade-in">
            {step.status === "loading" ? (
              <span className="flex h-4 w-4 shrink-0 items-center justify-center rounded-full bg-emerald-50 text-emerald-600 relative mt-0.5">
                <span className="animate-ping absolute inline-flex h-2.5 w-2.5 rounded-full bg-emerald-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-1.5 w-1.5 bg-emerald-600"></span>
              </span>
            ) : (
              <span className="flex h-4 w-4 shrink-0 items-center justify-center rounded-full bg-emerald-100 text-[#008069] text-[9px] font-black mt-0.5">
                ✓
              </span>
            )}
            <span className={cn(
              "font-medium leading-tight",
              step.status === "complete" ? "text-gray-400 font-normal" : "text-emerald-950 font-semibold"
            )}>
              {step.text}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
};

const TypewriterMarkdown = ({
  content,
  shouldAnimate,
  onComplete,
  onShowMasterProfile,
}: {
  content: string;
  shouldAnimate: boolean;
  onComplete?: () => void;
  onShowMasterProfile?: () => void;
}) => {
  const [displayedText, setDisplayedText] = useState(shouldAnimate ? "" : content);

  useEffect(() => {
    if (!shouldAnimate) {
      setDisplayedText(content);
      return;
    }

    const words = content.split(" ");
    let index = 0;

    const timer = setInterval(() => {
      if (index < words.length) {
        const increment = Math.min(3, words.length - index);
        index += increment;
        setDisplayedText(words.slice(0, index).join(" "));
      } else {
        clearInterval(timer);
        if (onComplete) onComplete();
      }
    }, 45);

    return () => clearInterval(timer);
  }, [content, shouldAnimate]);

  return (
    <ReactMarkdown
      components={{
        a: ({ href, children }) => {
          if (href === "#profile") {
            return (
              <button
                type="button"
                onClick={onShowMasterProfile}
                className="font-black text-[#008069] underline decoration-dotted underline-offset-2 hover:bg-green-50 px-0.5 rounded transition-colors cursor-pointer"
              >
                {children}
              </button>
            );
          }
          return (
            <a
              href={href}
              target="_blank"
              rel="noreferrer"
              className="text-blue-600 hover:underline"
            >
              {children}
            </a>
          );
        },
      }}
    >
      {displayedText}
    </ReactMarkdown>
  );
};

