  const fetchRecommendations = async () => {
    if (isProfileIncomplete) return;
    setLoading(true);
    try {
      const res = await getProfileRecommendations(userProfile);
      setData(res);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

