let globalAudioContext: AudioContext | null = null;
let currentAudioSource: AudioBufferSourceNode | null = null;
let currentHTMLAudio: HTMLAudioElement | null = null;
const audioCache = new Map<string, AudioBuffer>();

const stopAllAudio = () => {
  if (currentAudioSource) {
    try {
      currentAudioSource.onended = null;
      currentAudioSource.stop();
    } catch (e) {
      console.warn("Error stopping audio source:", e);
    }
    currentAudioSource = null;
  }
  if (currentHTMLAudio) {
    try {
      currentHTMLAudio.pause();
      currentHTMLAudio.src = "";
      currentHTMLAudio.load();
    } catch (e) {
      console.warn("Error stopping HTML audio:", e);
    }
    currentHTMLAudio = null;
  }
  if (typeof window !== "undefined" && window.speechSynthesis) {
    try {
      window.speechSynthesis.cancel();
    } catch (e) {
      console.warn("Error stopping speech synthesis:", e);
    }
  }
};

const resizeImage = (base64Str: string, maxDim = 1200): Promise<string> => {
  return new Promise((resolve) => {
    const img = new Image();
    img.src = base64Str;
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement("canvas");
      let width = img.width;
      let height = img.height;

      if (width > height) {
        if (width > maxDim) {
          height *= maxDim / width;
          width = maxDim;
        }
      } else {
        if (height > maxDim) {
          width *= maxDim / height;
          height = maxDim;
        }
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext("2d");
      if (ctx) {
        ctx.imageSmoothingEnabled = true;
        ctx.imageSmoothingQuality = "high";
        ctx.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL("image/jpeg", 0.8));
      } else {
        resolve(base64Str);
      }
    };
    img.onerror = () => resolve(base64Str);
  });
};

const getAudioContext = () => {
  if (!globalAudioContext) {
    globalAudioContext = new (
      window.AudioContext || (window as any).webkitAudioContext
    )();
  }
  return globalAudioContext;
};

const playAudio = async (
  text: string,
  onStart?: () => void,
  onEnd?: () => void,
) => {
  if (!text) return;

  const ctx = getAudioContext();
  if (ctx.state === "suspended") await ctx.resume();

  // Stop current audio if playing to avoid overlaps
  if (currentAudioSource) {
    try {
      currentAudioSource.onended = null;
      currentAudioSource.stop();
    } catch (e) {
      console.warn("Error stopping previous audio:", e);
    }
    currentAudioSource = null;
  }

  if (currentHTMLAudio) {
    try {
      currentHTMLAudio.pause();
      currentHTMLAudio.src = "";
      currentHTMLAudio.load();
    } catch (e) {
      console.warn("Error stopping previous HTML audio:", e);
    }
    currentHTMLAudio = null;
  }

  try {
    const cleanText = text.replace(/[#*`]/g, "").trim();
    if (!cleanText) return;

    // Use browser speech if offline as a fallback
    if (!navigator.onLine) {
      onStart?.();
      const utterance = new SpeechSynthesisUtterance(cleanText);
      const voices = window.speechSynthesis.getVoices();
      // Try to find a Hinglish or Hindi sounding voice
      const preferredVoice =
        voices.find((v) => v.lang.includes("hi") || v.lang.includes("in")) ||
        voices[0];
      if (preferredVoice) utterance.voice = preferredVoice;
      utterance.pitch = 1.1;
      utterance.rate = 1.0;
      utterance.onend = () => onEnd?.();
      utterance.onerror = () => onEnd?.();
      window.speechSynthesis.speak(utterance);
      return;
    }

    let buffer: AudioBuffer;

    if (audioCache.has(cleanText)) {
      buffer = audioCache.get(cleanText)!;
    } else {
      onStart?.();
      // Convert base64 to ArrayBuffer robustly
      const base64 = await getSpeech(cleanText);
      if (!base64) {
        onEnd?.();
        return;
      }
      console.log("Decoding audio data, length:", base64.length);

      try {
        // Remove padding/newlines and validate base64
        const cleanBase64 = base64.trim().replace(/[^A-Za-z0-9+/=]/g, "");
        const binaryString = window.atob(cleanBase64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let i = 0; i < len; i++) {
          bytes[i] = binaryString.charCodeAt(i);
        }

        try {
          // decodeAudioData is the preferred way
          buffer = await ctx.decodeAudioData(bytes.buffer.slice(0));
          audioCache.set(cleanText, buffer);
        } catch (decodeErr) {
          console.warn(
            "AudioContext.decodeAudioData failed, trying HTML Audio fallback. Error:",
            decodeErr,
          );

          // Fallback to HTML5 Audio element
          console.warn("decodeAudioData failed, trying HTML Audio fallback...");

          // Try to detect common format headers
          let mimeType = "audio/mpeg"; // Default

          if (bytes.length > 8) {
            const header =
              ((bytes[0] << 24) |
                (bytes[1] << 16) |
                (bytes[2] << 8) |
                bytes[3]) >>>
              0;
            const header2 =
              ((bytes[4] << 24) |
                (bytes[5] << 16) |
                (bytes[6] << 8) |
                bytes[7]) >>>
              0;

            // Log magic bytes for debugging to help fix future issues
            const hex = Array.from(bytes.slice(0, 8))
              .map((b) => b.toString(16).padStart(2, "0"))
              .join(" ");
            console.log(`Audio Magic Bytes (hex): ${hex}`);

            if (header === 0x52494646)
              mimeType = "audio/wav"; // "RIFF"
            else if ((header & 0xffffff00) === 0x49443300)
              mimeType = "audio/mpeg"; // ID3
            else if (bytes[0] === 0xff && (bytes[1] & 0xe0) === 0xe0)
              mimeType = "audio/mpeg"; // MP3 Sync
            else if (header === 0x1a45dfa3)
              mimeType = "audio/webm"; // WebM
            else if (header === 0x4f676753)
              mimeType = "audio/ogg"; // Ogg
            else if (header === 0x664c6143)
              mimeType = "audio/flac"; // fLaC
            else if (header === 0x00000018 || header === 0x00000020)
              mimeType = "audio/mp4"; // ftyp
          }

          // Use Blob and createObjectURL
          const blob = new Blob([bytes], { type: mimeType });
          const url = URL.createObjectURL(blob);
          const audio = new Audio();
          currentHTMLAudio = audio;
          audio.src = url;

          return new Promise<void>((resolve) => {
            const cleanup = () => {
              URL.revokeObjectURL(url);
              if (currentHTMLAudio === audio) currentHTMLAudio = null;
              onEnd?.();
              resolve();
            };

            const fallbackToSpeechSync = () => {
              console.log(
                "Both methods failed, falling back to SpeechSynthesis...",
              );
              const utterance = new SpeechSynthesisUtterance(cleanText);
              const voices = window.speechSynthesis.getVoices();
              const preferredVoice =
                voices.find(
                  (v) => v.lang.includes("hi") || v.lang.includes("in"),
                ) || voices[0];
              if (preferredVoice) utterance.voice = preferredVoice;

              let ended = false;
              const safeCleanup = () => {
                if (ended) return;
                ended = true;
                cleanup();
              };

              utterance.onend = safeCleanup;
              utterance.onerror = safeCleanup;

              // Extreme fallback timeout for speech synthesis
              setTimeout(safeCleanup, 8000);

              window.speechSynthesis.speak(utterance);
            };

            audio.onended = cleanup;
            audio.onerror = (e) => {
              console.error(
                `HTML Audio fallback error (MIME: ${mimeType}):`,
                e,
              );
              fallbackToSpeechSync();
            };

            audio.play().catch((playErr) => {
              console.warn(
                "Audio playback failed (fallback):",
                playErr.name,
                playErr.message,
              );
              fallbackToSpeechSync();
            });
          });
        }
      } catch (base64Err) {
        console.error("Base64 processing error:", base64Err);
        onEnd?.();
        return;
      }
    }

    onStart?.();
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);

    source.onended = () => {
      if (currentAudioSource === source) {
        currentAudioSource = null;
      }
      onEnd?.();
    };

    currentAudioSource = source;
    source.start(0);
  } catch (error) {
    console.error("Audio Playback Error:", error);
    currentAudioSource = null;
    onEnd?.();
  }
};

// Pub-sub global voice manager
const globalVoice = {
  playingText: null as string | null,
  status: "idle" as "idle" | "playing" | "paused",
  listeners: new Set<(state: { playingText: string | null; status: "idle" | "playing" | "paused" }) => void>(),
  
  set(playingText: string | null, status: "idle" | "playing" | "paused") {
    this.playingText = playingText;
    this.status = status;
    this.listeners.forEach(l => l({ playingText, status }));
  },
  
  subscribe(l: (state: { playingText: string | null; status: "idle" | "playing" | "paused" }) => void) {
    this.listeners.add(l);
    return () => {
      this.listeners.delete(l);
    };
  }
};

const pauseAllAudio = () => {
  if (typeof window !== "undefined" && window.speechSynthesis) {
    if (window.speechSynthesis.speaking && !window.speechSynthesis.paused) {
      window.speechSynthesis.pause();
    }
  }
  if (currentHTMLAudio) {
    currentHTMLAudio.pause();
  }
  if (globalAudioContext && globalAudioContext.state === "running") {
    globalAudioContext.suspend().catch(e => console.warn(e));
  }
};

const resumeAllAudio = async () => {
  if (typeof window !== "undefined" && window.speechSynthesis) {
    if (window.speechSynthesis.paused) {
      window.speechSynthesis.resume();
    }
  }
  if (currentHTMLAudio) {
    currentHTMLAudio.play().catch(e => console.warn("Error resuming HTML Audio:", e));
  }
  if (globalAudioContext && globalAudioContext.state === "suspended") {
    await globalAudioContext.resume().catch(e => console.warn(e));
  }
};

const PlayButton = ({ text }: { text: string }) => {
  const [globalState, setGlobalState] = useState({
    playingText: globalVoice.playingText,
    status: globalVoice.status,
  });
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    return globalVoice.subscribe((newState) => {
      setGlobalState(newState);
    });
  }, []);

  const isCurrentText = globalState.playingText === text;
  const isPlaying = isCurrentText && globalState.status === "playing";
  const isPaused = isCurrentText && globalState.status === "paused";

  const handlePlayOrResume = async () => {
    if (isLoading) return;

    if (isPaused) {
      await resumeAllAudio();
      globalVoice.set(text, "playing");
      return;
    }

    // Stop previous to prevent overlay
    stopAllAudio();
    setIsLoading(true);
    await playAudio(
      text,
      () => {
        setIsLoading(false);
        globalVoice.set(text, "playing");
      },
      () => {
        setIsLoading(false);
        if (globalVoice.playingText === text) {
          globalVoice.set(null, "idle");
        }
      },
    );
  };

  const handleHold = () => {
    pauseAllAudio();
    globalVoice.set(text, "paused");
  };

  const handleStop = () => {
    stopAllAudio();
    globalVoice.set(null, "idle");
  };

  return (
    <div className="flex items-center gap-1 bg-slate-100/90 p-1.5 rounded-2xl border border-slate-250/75 shadow-xs shrink-0 select-none">
      {/* Play / Hold main controller */}
      {isCurrentText ? (
        isPlaying ? (
          <button
            onClick={(e) => {
              e.stopPropagation();
              handleHold();
            }}
            className="px-2.5 py-1 rounded-xl bg-orange-600 hover:bg-orange-700 text-white font-sans text-[10px] font-black uppercase tracking-wider transition-all flex items-center gap-1 cursor-pointer border-none shadow-xs"
            title="Aawaz Rokein / Hold Voice"
          >
            <Pause className="w-3.5 h-3.5" />
            <span>Hold</span>
          </button>
        ) : isPaused ? (
          <button
            onClick={(e) => {
              e.stopPropagation();
              handlePlayOrResume();
            }}
            className="px-2.5 py-1 rounded-xl bg-[#008069] hover:bg-[#005c4b] text-white font-sans text-[10px] font-black uppercase tracking-wider transition-all flex items-center gap-1 cursor-pointer border-none shadow-xs"
            title="Sunein / Resume Voice"
          >
            <Play className="w-3.5 h-3.5 fill-current" />
            <span>Play</span>
          </button>
        ) : null
      ) : (
        <button
          onClick={(e) => {
            e.stopPropagation();
            handlePlayOrResume();
          }}
          disabled={isLoading}
          className={cn(
            "px-2.5 py-1 rounded-xl font-sans text-[10px] font-black uppercase tracking-wider transition-all flex items-center gap-1 cursor-pointer border shadow-neutral-100/30",
            isLoading
              ? "bg-slate-200 text-slate-400 border-transparent cursor-not-allowed"
              : "bg-white text-slate-700 hover:bg-slate-50 border-slate-250/60 hover:border-slate-350"
          )}
          title="Listen/Speak in Hindi/Hinglish"
        >
          {isLoading ? (
            <RefreshCw className="w-3 h-3 animate-spin text-[#008069]" />
          ) : (
            <Volume2 className="w-3.5 h-3.5" />
          )}
          <span>{isLoading ? "Sunein..." : "Sunein"}</span>
        </button>
      )}

      {/* Stop / Baand controller if this message is actively selected */}
      {isCurrentText && (
        <button
          onClick={(e) => {
            e.stopPropagation();
            handleStop();
          }}
          className="px-2.5 py-1 rounded-xl bg-red-150 hover:bg-red-200 text-red-700 font-sans text-[10px] font-black uppercase tracking-wider transition-all flex items-center gap-1 cursor-pointer border border-red-250/50 shadow-xs"
          title="Voice Baand Karein / Stop Audio"
        >
          <X className="w-3.5 h-3.5 font-black" />
          <span>Baand</span>
        </button>
      )}
    </div>
  );
};

