const getProfileBasedSuggestions = (profile: UserProfile): string[] => {
  const normState = (profile.state || "").toLowerCase();
  const normComm = (profile.community || "Normal").toLowerCase();
  const normOcc = (profile.occupation || "").toLowerCase();
  const normCat = (profile.category || "").toLowerCase();
  const normGen = (profile.gender || "").toLowerCase();

  const pool: string[] = [...SUGGESTION_POOLS.general];

  if (normComm === "student" || normOcc === "student" || profile.class) {
    pool.push(...SUGGESTION_POOLS.student);
  }

  if (
    normComm === "jobs" ||
    normOcc === "naukri" ||
    normOcc === "worker" ||
    normOcc === "unemployed"
  ) {
    pool.push(...SUGGESTION_POOLS.jobs);
  }

  if (normState.includes("bihar")) {
    pool.push(...SUGGESTION_POOLS.bihar);
  } else if (
    normState.includes("up") ||
    normState.includes("uttar") ||
    normState.includes("pradesh")
  ) {
    pool.push(...SUGGESTION_POOLS.up);
  }

  if (
    normCat === "sc" ||
    normCat === "st" ||
    normCat === "obc" ||
    normCat === "ews"
  ) {
    pool.push(...SUGGESTION_POOLS.deprived);
  }

  if (normGen === "female" || normGen === "girl") {
    pool.push(...SUGGESTION_POOLS.female);
  }

  // Shuffle logic
  const shuffled = [...pool].sort(() => 0.5 - Math.random());

  // Return top 6-7 unique items, always offering a good variety
  const uniqueSuggestions = Array.from(new Set(shuffled));
  return uniqueSuggestions.slice(0, 6);
};

const ChatScreen = ({
  initialMessage,
  onMessageConsumed,
  userProfile,
  onNavigate,
  onSetTargetSchemeId,
  schemes,
  onShowMasterProfile,
  onShowFeedback,
}: {
  initialMessage?: string;
  onMessageConsumed?: () => void;
  userProfile: UserProfile;
  onNavigate: (v: string) => void;
  onSetTargetSchemeId: (id: string) => void;
  schemes: Scheme[];
  onShowMasterProfile: () => void;
  onShowFeedback: (
    type?: any,
    relatedId?: string,
    relatedName?: string,
  ) => void;
}) => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [activeConversationId, setActiveConversationId] = useState<
    string | null
  >(null);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: "welcome",
      role: "assistant",
      content:
        "Namaste! Main aapka **Form Mitra** (aapka Bade Bhai) hoon. Main aapki sarkari schemes, career aur forms bharne mein 100% help karunga. \n\nAaj kaise help karu bhai? \n\n*Hinglish, Hindi ya English mein baat kar sakte hain.*",
      timestamp: Date.now(),
    },
  ]);
  const [input, setInput] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [animatedMessageIds, setAnimatedMessageIds] = useState<Record<string, boolean>>({});
  const [isHistoryLoading, setIsHistoryLoading] = useState(true);
  const [isListening, setIsListening] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isGeneratingRef = useRef(false);

  const handleStopGeneration = () => {
    isGeneratingRef.current = false;
    setIsTyping(false);
    stopAllAudio();
    showToast("Response generation stopped.", "info");
  };

  const [activeSuggestions, setActiveSuggestions] = useState<string[]>([]);

  useEffect(() => {
    setActiveSuggestions(getProfileBasedSuggestions(userProfile));
  }, [userProfile, activeConversationId]);

  const handleShuffleSuggestions = () => {
    setActiveSuggestions(getProfileBasedSuggestions(userProfile));
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = event.target?.result as string;
        const lowRes = await resizeImage(base64, 800);
        setSelectedImage(lowRes);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMessageRating = async (
    messageId: string,
    rating: "up" | "down",
  ) => {
    if (!auth.currentUser || !activeConversationId) return;

    // Optimistic update
    setMessages((prev) =>
      prev.map((m) => (m.id === messageId ? { ...m, rating } : m)),
    );

    try {
      const path = `users/${auth.currentUser.uid}/conversations/${activeConversationId}/messages/${messageId}`;
      await updateDoc(doc(db, path), { rating });
      showToast(
        rating === "up"
          ? "Shukriya! Aapko response pasand aaya."
          : "Feedback noted. Hum ise behtar karenge.",
        "info",
      );
    } catch (err) {
      handleFirestoreError(
        err,
        OperationType.UPDATE,
        `users/${auth.currentUser.uid}/conversations/${activeConversationId}/messages/${messageId}`,
      );
    }
  };

  // Fetch conversations
  useEffect(() => {
    if (!auth.currentUser) return;
    setIsHistoryLoading(true);
    const q = query(
      collection(db, `users/${auth.currentUser.uid}/conversations`),
      where("userId", "==", auth.currentUser.uid),
    );

    const unsubscribe = onSnapshot(
      q,
      (snapshot) => {
        const convs = snapshot.docs.map(
          (doc) => ({ id: doc.id, ...doc.data() }) as Conversation,
        );
        setConversations(convs.sort((a, b) => b.updatedAt - a.updatedAt));
        setIsHistoryLoading(false);
      },
      (error) => {
        handleFirestoreError(error, OperationType.LIST, "conversations");
        setIsHistoryLoading(false);
      },
    );

    return () => unsubscribe();
  }, []);

  // Listen for messages in active conversation
  useEffect(() => {
    if (!auth.currentUser || !activeConversationId) {
      if (!activeConversationId) {
        setMessages([
          {
            id: "welcome",
            role: "assistant",
            content:
              "Namaste! Main aapka **Form Mitra** (aapka Bade Bhai) hoon. Main aapki sarkari schemes, career aur forms bharne mein 100% help karunga. \n\nAaj kaise help karu bhai? \n\n*Hinglish, Hindi ya English mein baat kar sakte hain.*",
            timestamp: Date.now(),
          },
        ]);
      }
      return;
    }

    const q = query(
      collection(
        db,
        `users/${auth.currentUser.uid}/conversations/${activeConversationId}/messages`,
      ),
    );

    const unsubscribe = onSnapshot(
      q,
      (snapshot) => {
        const msgs = snapshot.docs.map(
          (doc) => ({ id: doc.id, ...doc.data() }) as Message,
        );
        const sorted = msgs.sort((a, b) => a.timestamp - b.timestamp);
        setMessages(sorted);
        if (sorted.length > 0 && sorted[sorted.length - 1].role === "assistant") {
          setIsTyping(false);
        }
      },
      (error) => handleFirestoreError(error, OperationType.LIST, "messages"),
    );

    return () => unsubscribe();
  }, [activeConversationId]);

  useEffect(() => {
    if (initialMessage) {
      handleInitialSend(initialMessage);
      onMessageConsumed?.();
    }
  }, [initialMessage]);

  const saveMessage = async (
    convId: string,
    role: string,
    content: string,
    thought?: string | null,
    image?: string | null,
  ) => {
    if (!auth.currentUser) return;
    const msgData = {
      role,
      content,
      thought: thought || null,
      image: image || null,
      timestamp: Date.now(),
      userId: auth.currentUser.uid,
    };

    try {
      await addDoc(
        collection(
          db,
          `users/${auth.currentUser.uid}/conversations/${convId}/messages`,
        ),
        msgData,
      );

      // Update conversation metadata
      await updateDoc(
        doc(db, `users/${auth.currentUser.uid}/conversations`, convId),
        {
          lastMessage: image
            ? "📸 Photo analysis request"
            : content.substring(0, 50) + (content.length > 50 ? "..." : ""),
          updatedAt: Date.now(),
        },
      );
    } catch (error) {
      handleFirestoreError(error, OperationType.CREATE, "messages");
    }
  };

  const createConversation = async (
    firstMessage: string,
    image?: string | null,
  ) => {
    if (!auth.currentUser) return null;
    try {
      const convData = {
        userId: auth.currentUser.uid,
        title: image
          ? "New Image Analysis"
          : firstMessage.substring(0, 30) +
            (firstMessage.length > 30 ? "..." : ""),
        lastMessage: image ? "Sent a photo" : firstMessage,
        updatedAt: Date.now(),
      };
      const docRef = await addDoc(
        collection(db, `users/${auth.currentUser.uid}/conversations`),
        convData,
      );
      return docRef.id;
    } catch (error) {
      handleFirestoreError(error, OperationType.CREATE, "conversations");
      return null;
    }
  };

  const handleInitialSend = async (text: string) => {
    isGeneratingRef.current = true;
    setIsTyping(true);
    let convId = activeConversationId;

    if (!convId) {
      convId = await createConversation(text);
      if (!convId) return;
      setActiveConversationId(convId);
    }

    await saveMessage(convId, "user", text);

    try {
      if (!auth.currentUser) return;
      const idToken = await auth.currentUser.getIdToken();
      
      await fetch("/api/chat/process", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${idToken}`
        },
        body: JSON.stringify({
          userId: auth.currentUser.uid,
          convId,
          userMessage: text,
          chatHistory: [],
          userProfile
        })
      });
    } catch (error) {
      console.error(error);
      if (!isGeneratingRef.current) return;
      showToast(
        "Server mein kuch dikkat hai. Kripya thodi der baad try karein.",
        "error",
      );
    }
  };

  const handleSend = async (textOverride?: string) => {
    if ((!textOverride && !input.trim() && !selectedImage) || !auth.currentUser)
      return;

    const text =
      textOverride ||
      input ||
      (selectedImage ? "Kripya is photo ko analyze karein." : "");

    if (text === "Generate WhatsApp Alert") {
      (window as any).showWhatsAppGenerator?.();
      setInput("");
      return;
    }

    const currentImg = selectedImage;
    const currentMime = mimeType;

    if (!textOverride) {
      setInput("");
    }
    setSelectedImage(null);
    setMimeType(null);
    isGeneratingRef.current = true;
    setIsTyping(true);

    let convId = activeConversationId;
    if (!convId) {
      convId = await createConversation(text, currentImg);
      if (!convId) return;
      setActiveConversationId(convId);
    }

    await saveMessage(convId, "user", text, null, currentImg);

    try {
      const history = messages.map((m) => {
        const parts: any[] = [{ text: m.content }];
        if (m.image) {
          const base64Data = m.image.split(",")[1];
          const mime = m.image.split(",")[0].split(":")[1].split(";")[0];
          parts.push({ inlineData: { data: base64Data, mimeType: mime } });
        }
        return {
          role: m.role === "assistant" ? ("model" as const) : ("user" as const),
          parts,
        };
      });

      const idToken = await auth.currentUser.getIdToken();
      await fetch("/api/chat/process", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${idToken}`
        },
        body: JSON.stringify({
          userId: auth.currentUser.uid,
          convId,
          userMessage: text,
          chatHistory: history,
          userProfile,
          imageBase64: currentImg?.split(",")[1] || null,
          mimeType: currentMime || null
        })
      });
    } catch (error) {
      console.error(error);
      if (!isGeneratingRef.current) return;
      showToast(
        "Server mein kuch dikkat hai. Kripya thodi der baad try karein.",
        "error",
      );
    }
  };

  const startVoiceInput = () => {
    const SpeechRecognition =
      (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Voice recognition not supported in this browser.");
      return;
    }
    const recognition = new SpeechRecognition();
    recognition.lang = "hi-IN";
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setInput(transcript);
    };
    recognition.start();
  };

  const deleteConversation = async (e: React.MouseEvent, convId: string) => {
    e.stopPropagation();
    if (
      !auth.currentUser ||
      !window.confirm("Bhai, kya aap ye conversation delete karna chahte hain?")
    )
      return;

    try {
      // First delete all messages
      const messagesRef = collection(
        db,
        `users/${auth.currentUser.uid}/conversations/${convId}/messages`,
      );
      const messagesSnap = await getDocs(messagesRef);
      const deletePromises = messagesSnap.docs.map((d) =>
        deleteDoc(
          doc(
            db,
            `users/${auth.currentUser.uid}/conversations/${convId}/messages`,
            d.id,
          ),
        ),
      );
      await Promise.all(deletePromises);

      // Then delete conversation metadata
      await deleteDoc(
        doc(db, `users/${auth.currentUser.uid}/conversations`, convId),
      );

      if (activeConversationId === convId) {
        startNewChat();
      }
    } catch (error) {
      handleFirestoreError(error, OperationType.DELETE, "conversations");
    }
  };

  const startNewChat = () => {
    setActiveConversationId(null);
    setMessages([
      {
        id: "welcome",
        role: "assistant",
        content:
          "Namaste! Main aapka **Form Mitra** (aapka Bade Bhai) hoon. Main aapki sarkari schemes, career aur forms bharne mein 100% help karunga. \n\nAaj kaise help karu bhai? \n\n*Hinglish, Hindi ya English mein baat kar sakte hain.*",
        timestamp: Date.now(),
      },
    ]);
    setShowHistory(false);
  };

  return (
    <div className="flex flex-col flex-1 h-full bg-[#E5DDD5] chat-pattern relative overflow-hidden">
      {/* History Sidebar/Drawer */}
      <AnimatePresence>
        {showHistory && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setShowHistory(false)}
              className="absolute inset-0 bg-black/40 z-40 backdrop-blur-sm"
            />
            <motion.div
              initial={{ x: "-100%" }}
              animate={{ x: 0 }}
              exit={{ x: "-100%" }}
              transition={{ type: "spring", damping: 25, stiffness: 200 }}
              className="absolute left-0 top-0 bottom-0 w-80 bg-white z-50 shadow-2xl flex flex-col"
            >
              <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-[#008069] text-white">
                <h3 className="font-black uppercase tracking-widest text-sm">
                  Chat History
                </h3>
                <button onClick={() => setShowHistory(false)}>
                  <X className="w-5 h-5" />
                </button>
              </div>

              <div className="p-3">
                <button
                  onClick={startNewChat}
                  className="w-full py-3 bg-green-50 text-[#008069] rounded-2xl font-black uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 hover:bg-green-100 transition-all border border-green-100"
                >
                  <Plus className="w-4 h-4" />
                  New Conversation
                </button>
              </div>

              <div className="flex-1 overflow-y-auto p-2 space-y-2">
                {isHistoryLoading ? (
                  <div className="space-y-2 p-1">
                    {[1, 2, 3, 4, 5].map((i) => (
                      <div
                        key={i}
                        className="p-3 bg-white border border-gray-100 rounded-2xl flex flex-col gap-2"
                      >
                        <div className="flex justify-between items-center">
                          <Skeleton className="h-4 w-1/2 rounded-md" />
                          <Skeleton className="h-3 w-12 rounded-sm" />
                        </div>
                        <Skeleton className="h-3 w-3/4 rounded-sm" />
                      </div>
                    ))}
                  </div>
                ) : conversations.length === 0 ? (
                  <div className="text-center py-10">
                    <History className="w-10 h-10 text-gray-200 mx-auto mb-2" />
                    <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">
                      No previous chats
                    </p>
                  </div>
                ) : (
                  conversations.map((conv) => (
                    <div key={conv.id} className="relative group">
                      <button
                        onClick={() => {
                          setActiveConversationId(conv.id);
                          setShowHistory(false);
                        }}
                        className={cn(
                          "w-full p-3 pr-10 rounded-2xl text-left border transition-all flex flex-col gap-1",
                          activeConversationId === conv.id
                            ? "bg-green-50 border-green-200"
                            : "bg-white border-gray-100 hover:border-green-100",
                        )}
                      >
                        <div className="flex justify-between items-start gap-2">
                          <h4 className="font-bold text-sm text-gray-900 line-clamp-1">
                            {conv.title}
                          </h4>
                          <span className="text-[8px] text-gray-400 font-black uppercase whitespace-nowrap">
                            {new Date(conv.updatedAt).toLocaleDateString()}
                          </span>
                        </div>
                        <p className="text-[10px] text-gray-500 line-clamp-1 font-medium">
                          {conv.lastMessage}
                        </p>
                      </button>
                      <button
                        onClick={(e) => deleteConversation(e, conv.id)}
                        className="absolute right-2 top-1/2 -translate-y-1/2 p-2 text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  ))
                )}
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>

      <div className="bg-white border-b border-gray-100 p-3 flex justify-between items-center shadow-sm z-10">
        <div className="flex items-center gap-3">
          <button
            onClick={() => setShowHistory(true)}
            className="w-10 h-10 rounded-full bg-gray-50 flex items-center justify-center text-gray-400 hover:bg-gray-100 transition-all border border-gray-100"
          >
            <History className="w-5 h-5" />
          </button>
          <div className="w-10 h-10 rounded-full bg-[#008069] flex items-center justify-center text-white font-bold text-xs uppercase shadow-inner">
            FM
          </div>
          <div>
            <h3 className="text-sm font-black text-gray-900 leading-tight">
              Form Mitra AI
            </h3>
            <p className="text-[10px] text-green-500 font-bold uppercase tracking-wider">
              {activeConversationId ? "Active Session" : "New Chat"}
            </p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          {activeConversationId && (
            <button
              onClick={startNewChat}
              className="p-2 text-gray-400 hover:text-[#008069] transition-colors"
              title="New Chat"
            >
              <Plus className="w-5 h-5" />
            </button>
          )}
          <button
            onClick={() => (window as any).startLiveCall()}
            className="p-2.5 rounded-full bg-green-50 text-[#008069] shadow-sm border border-green-100 hover:bg-green-100 transition-colors"
          >
            <Mic className="w-5 h-5" />
          </button>
        </div>
      </div>
      <div className="flex-1 overflow-y-auto p-4 space-y-4 pb-20">
        {messages.map((m) => (
          <div
            key={m.id}
            className={cn(
              "flex flex-col max-w-[85%] rounded-2xl p-3 shadow-sm relative",
              m.role === "user"
                ? "ml-auto bg-[#DCF8C6] text-gray-800 rounded-tr-none border border-[#C7E9B0]"
                : "mr-auto bg-white text-gray-900 border border-gray-100 rounded-tl-none",
            )}
          >
            {m.role === "assistant" && m.thought && (
              <details className="mb-2 text-[10px] text-gray-400 bg-gray-50 p-2 rounded-xl border border-gray-100 group">
                <summary className="cursor-pointer font-bold uppercase tracking-widest list-none flex items-center gap-1 group-open:mb-2">
                  <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-pulse" />
                  Mitra's Thought Process
                </summary>
                <div className="italic font-medium leading-relaxed opacity-80">
                  {m.thought}
                </div>
              </details>
            )}

            {m.image && (
              <div className="mb-3 rounded-xl overflow-hidden border border-black/5 bg-black/5">
                <img
                  src={m.image}
                  alt="User Upload"
                  className="w-full object-contain max-h-60"
                />
              </div>
            )}

            <div className="prose prose-sm prose-p:my-1 prose-ul:my-1 prose-li:my-0 mt-0.5 text-inherit">
              {(() => {
                const processed = (() => {
                  if (m.role !== "assistant") return m.content;

                  const terms = [
                    userProfile.state,
                    userProfile.community,
                    userProfile.occupation,
                    userProfile.category,
                    userProfile.monthlyIncome,
                  ].filter((t): t is string => !!t && t.length > 2);

                  const uniqueTerms = Array.from(new Set(terms)).sort(
                    (a, b) => b.length - a.length,
                  );

                  let txt = m.content;
                  uniqueTerms.forEach((term) => {
                    const escapedTerm = term.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
                    const regex = new RegExp(`\\b(${escapedTerm})\\b`, "gi");
                    txt = txt.replace(regex, (match) => {
                      if (txt.includes(`[${match}](#profile)`)) return match;
                      return `[${match}](#profile)`;
                    });
                  });
                  return txt;
                })();

                const isLastMsg = messages[messages.length - 1]?.id === m.id;
                const shouldAnimate = m.role === "assistant" && m.id !== "welcome" && isLastMsg && !animatedMessageIds[m.id];

                if (m.role === "assistant") {
                  return (
                    <TypewriterMarkdown
                      content={processed}
                      shouldAnimate={shouldAnimate}
                      onComplete={() => setAnimatedMessageIds((prev) => ({ ...prev, [m.id]: true }))}
                      onShowMasterProfile={onShowMasterProfile}
                    />
                  );
                } else {
                  return <ReactMarkdown>{processed}</ReactMarkdown>;
                }
              })()}
            </div>

            {m.role === "assistant" && m.id !== "welcome" && (
              <div className="flex items-center justify-between mt-3 pt-2 border-t border-gray-50/50">
                <div className="flex items-center gap-1">
                  <button
                    onClick={() => handleMessageRating(m.id, "up")}
                    className={cn(
                      "p-1.5 rounded-lg transition-all",
                      m.rating === "up"
                        ? "bg-green-100 text-[#008069]"
                        : "text-gray-300 hover:text-green-500 hover:bg-green-50",
                    )}
                  >
                    <ThumbsUp className="w-3.5 h-3.5" />
                  </button>
                  <button
                    onClick={() => handleMessageRating(m.id, "down")}
                    className={cn(
                      "p-1.5 rounded-lg transition-all",
                      m.rating === "down"
                        ? "bg-red-100 text-red-600"
                        : "text-gray-300 hover:text-red-500 hover:bg-red-50",
                    )}
                  >
                    <ThumbsDown className="w-3.5 h-3.5" />
                  </button>
                </div>

                <div className="flex items-center gap-2">
                  <PlayButton text={m.content} />
                  {m.rating === "down" && (
                    <button
                      onClick={() =>
                        onShowFeedback("issue", m.id, "AI Response")
                      }
                      className="text-[9px] font-black uppercase text-[#008069] tracking-widest bg-green-50 px-2 py-1.5 rounded-lg hover:bg-green-100 transition-all border border-green-100"
                    >
                      Report Issue
                    </button>
                  )}
                </div>
              </div>
            )}

            {m.role === "assistant" && m.id === "welcome" && (
              <div className="mt-3 pt-2 border-t border-gray-50/50 flex justify-end">
                <PlayButton text={m.content} />
              </div>
            )}

            {m.role === "assistant" &&
              (() => {
                const mentionedScheme = schemes.find(
                  (s) =>
                    m.content.toLowerCase().includes(s.name.toLowerCase()) ||
                    (s.hindiName &&
                      m.content
                        .toLowerCase()
                        .includes(s.hindiName.toLowerCase())),
                );
                if (mentionedScheme) {
                  return (
                    <button
                      onClick={() => {
                        onSetTargetSchemeId(mentionedScheme.id);
                        onNavigate("schemes");
                      }}
                      className="mt-3 self-start flex items-center gap-1.5 px-3 py-2 rounded-xl bg-slate-900 text-white text-[9px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-md group"
                    >
                      <LayoutGrid className="w-3.5 h-3.5 group-hover:rotate-90 transition-transform" />
                      View {mentionedScheme.hindiName || mentionedScheme.name}{" "}
                      Details
                    </button>
                  );
                }
                return null;
              })()}

            <div className="flex items-center justify-end mt-2 pt-1 border-t border-black/5">
              <span className={cn("text-[9px] opacity-40 font-bold")}>
                {new Date(m.timestamp).toLocaleTimeString([], {
                  hour: "2-digit",
                  minute: "2-digit",
                })}
              </span>
            </div>

            {m.role === "assistant" &&
              (m.content.includes("scheme") ||
                m.content.includes("verify") ||
                m.content.includes("website")) && (
                <button
                  onClick={() =>
                    setInput(
                      `VERIFY_OFFICIAL: Kripya is scheme/jaankari ko official website se re-check karein aur latest 2026 data batayein.`,
                    )
                  }
                  className="mt-3 self-start flex items-center gap-1.5 px-3 py-1.5 rounded-xl bg-[#008069]/10 text-[#008069] text-[9px] font-black uppercase tracking-widest hover:bg-[#008069]/20 transition-all border border-[#008069]/20 shadow-sm"
                >
                  <Globe className="w-3.5 h-3.5" />
                  RE-CHECK Official Website
                </button>
              )}
          </div>
        ))}
        {isTyping && (
          <div className="mr-auto bg-white p-5 rounded-[2.5rem] rounded-tl-none border border-gray-100 shadow-xl flex flex-col gap-3 max-w-[85%]">
            <AILoader message="Mitra is thinking & browsing..." />
            <ThinkingStepsRenderer />
          </div>
        )}
      </div>

      <div className="p-2 sm:p-3 bg-gray-50 border-t border-gray-200/80 flex flex-col gap-2 z-20 shrink-0">
        {messages.length <= 1 && !selectedImage && (
          <div className="flex flex-col gap-1.5 mb-1">
            <div className="flex justify-between items-center px-1">
              <p className="text-[9px] sm:text-[10px] font-black text-gray-500 uppercase tracking-widest">
                💡 AI Suggestions for {userProfile.state || "India"} sathi (
                {userProfile.community || "Normal"})
              </p>
              <button
                type="button"
                onClick={handleShuffleSuggestions}
                className="p-1 rounded-full bg-white hover:bg-green-50 text-[#008069] border border-gray-200 transition-all active:scale-95 cursor-pointer flex items-center justify-center shadow-sm"
                title="Shuffle suggestions / Naye Sawaal"
                id="mitra-suggestions-shuffle-btn"
              >
                <RefreshCw className="w-3 h-3" />
              </button>
            </div>
            <div className="flex gap-1.5 overflow-x-auto pb-1.5 pt-0.5 scrollbar-hide">
              {activeSuggestions.map((s) => (
                <button
                  key={s}
                  onClick={() => handleSend(s)}
                  className="whitespace-nowrap px-3.5 py-2 rounded-full bg-white border border-gray-200 text-[#008069] text-[9.5px] font-bold shadow-sm active:scale-95 transition-all hover:border-[#008069] cursor-pointer hover:bg-green-50/25"
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}
        {selectedImage && (
          <div className="flex gap-2 p-2 bg-white rounded-2xl border border-gray-200">
            <div className="relative">
              <img
                src={selectedImage}
                alt="Preview"
                className="w-14 h-14 rounded-xl object-cover"
              />
              <button
                onClick={() => setSelectedImage(null)}
                className="absolute -top-1.5 -right-1.5 bg-red-500 text-white p-1 rounded-full shadow-lg"
              >
                <X className="w-2.5 h-2.5" />
              </button>
            </div>
            <div className="flex-1 flex flex-col justify-center">
              <p className="text-[9px] font-black uppercase tracking-widest text-gray-400">
                Photo Attached
              </p>
              <p className="text-[10px] text-gray-600 font-medium">
                Ready to analyze
              </p>
            </div>
          </div>
        )}
        <div className="flex gap-1.5 sm:gap-2.5 items-center w-full min-w-0">
          <input
            type="file"
            ref={fileInputRef}
            onChange={handleImageSelect}
            accept="image/*"
            className="hidden"
          />
          
          {/* Quick attachment Actions */}
          <div className="flex gap-1 sm:gap-1.5 items-center shrink-0">
            <button
              onClick={() => fileInputRef.current?.click()}
              className="p-2 sm:p-2.5 rounded-full bg-white text-[#008069] hover:bg-green-50 active:scale-90 transition-all border border-gray-200 shadow-sm flex items-center justify-center shrink-0"
              title="Attach Image"
            >
              <Paperclip className="w-4.5 h-4.5" />
            </button>
            <button
              onClick={() => {
                // Open camera by triggering file input with capture attribute
                if (fileInputRef.current) {
                  fileInputRef.current.setAttribute("capture", "environment");
                  fileInputRef.current.click();
                  // Reset capture attribute after a delay so standard selection works next time
                  setTimeout(
                    () => fileInputRef.current?.removeAttribute("capture"),
                    1000,
                  );
                }
              }}
              className="p-2 sm:p-2.5 rounded-full bg-white text-orange-600 hover:bg-orange-50 active:scale-90 transition-all border border-gray-200 shadow-sm flex items-center justify-center shrink-0"
              title="Take Photo"
            >
              <Camera className="w-4.5 h-4.5" />
            </button>
            <button
              onClick={() => {
                const url = prompt(
                  "Kripya government website ka link yahan paste karein (Example: pmkisan.gov.in):",
                );
                if (url) {
                  setInput(
                    `Is website ko analyze karein aur iske schemes ke baare mein batayein: ${url}`,
                  );
                }
              }}
              className="p-2 sm:p-2.5 rounded-full bg-white text-[#008069] hover:bg-green-50 active:scale-90 transition-all border border-gray-200 shadow-sm flex items-center justify-center hidden sm:flex shrink-0"
              title="Analyze Website"
            >
              <Globe className="w-4.5 h-4.5" />
            </button>
            <button
              onClick={startVoiceInput}
              className={cn(
                "p-2 sm:p-2.5 rounded-full transition-all shadow-sm border shrink-0 flex items-center justify-center",
                isListening
                  ? "bg-red-500 text-white animate-pulse border-red-500"
                  : "bg-white text-green-600 border-gray-200 hover:bg-green-50",
              )}
              title={isListening ? "Listening / Awaaj Sunn Raha Hoon..." : "Speak / Awaaj Se Likhein"}
            >
              {isListening ? <MicOff className="w-4.5 h-4.5" /> : <Mic className="w-4.5 h-4.5" />}
            </button>
          </div>

          {/* Chat text input container */}
          <div className="flex-1 bg-white h-10 sm:h-11 rounded-full border border-gray-200 flex items-center px-4 shadow-sm min-w-0">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && !isTyping && handleSend()}
              placeholder={
                isListening ? "Listening..." : "Hinglish mein puhein..."
              }
              className="flex-1 text-xs sm:text-sm outline-none bg-transparent min-w-0 font-medium text-gray-800 placeholder-gray-400"
              disabled={isTyping}
            />
          </div>

          {/* Premium action handler: Send or Stop/Hold */}
          {isTyping ? (
            <button
              onClick={handleStopGeneration}
              className="w-10 h-10 sm:w-11 sm:h-11 rounded-full bg-rose-600 hover:bg-rose-700 active:scale-90 text-white shadow-md shadow-rose-100 flex items-center justify-center transition-all shrink-0 cursor-pointer"
              title="Stop Generation / Rokein"
            >
              <Square className="w-3.5 h-3.5 fill-current text-white animate-pulse" />
            </button>
          ) : (
            <button
              onClick={() => handleSend()}
              disabled={!input.trim() && !selectedImage}
              className={cn(
                "w-10 h-10 sm:w-11 sm:h-11 rounded-full text-white shadow-md transition-all shrink-0 flex items-center justify-center active:scale-90 cursor-pointer",
                (!input.trim() && !selectedImage)
                  ? "bg-gray-300 shadow-none cursor-not-allowed opacity-50"
                  : "bg-[#008069] hover:bg-[#005c4b] shadow-green-100/50"
              )}
              title="Send Message"
            >
              <Send className="w-4 h-4 text-white" />
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

